interceptor.preaction:

						String measure_dt = rrequest.getStringAttribute("MEASURE_DT", "");// 取出输入的查询时间
						System.out.println("measure_dt:" + measure_dt);
						if (measure_dt.equals("")) 
						{
							Connection conn = rrequest.getConnection();
							PreparedStatement pstmt = null;
							try {
									String SQL = "Select DATA_DT from IBS.T8_DATA_DT";
									pstmt = conn.prepareStatement(SQL);
									ResultSet resultSet = pstmt.executeQuery();
									while (resultSet.next()) {
					                     String date=resultSet.getString("DATA_DT");
					                     rrequest.setAttribute("MEASURE_DT", date);
										 measure_dt=date;
				                    }
									System.out.println("measure_dt处理后时间为:" + measure_dt);
									resultSet.close();
									pstmt.close();
								} 
							catch (Exception e) {
									e.printStackTrace();
							}
                        }

select.value:
select sy.* ,(case when gd.EMP_TYPE='过渡期' then '是' else '' end) as EMP_GDQ ,em.EMP_TYPE as EMP_POS ,ce.GRADE ,em.EMP_NM ,ty.PSTN_TYPE_NM ,ty.SUB_PSTN_TYPE_NM from( select left(sy.MEASURE_DT,4) as EXAM_YEAR ,right(sy.MEASURE_DT,5) as EXAM_Q ,sy.MEASURE_DT ,q.QTD_NM ,q.QTD ,sy.EMP_ID
,sy.ORG_ID ,og.ORG_NM ,og.BRANCH_ORG_ID ,og.BRANCH_ORG_NM ,og.HEAD_ORG_ID ,sy.PSTN_TYPE ,sy.SUB_PSTN_TYPE ,sy.GRADE ,sy.RESOURCE_MANAGER_F ,(DEP_Q_PROFIT+LN_Q_PROFIT+IB_Q_BONUS) as PROFIT ,sum(DEP_Q_PROFIT+LN_Q_PROFIT+IB_Q_BONUS) over(partition by sy.EMP_ID) as PROFIT_YTD from ibs.T7_EMP_SMY sy inner JOIN IBS.T5_ORG og ON sy.ORG_ID = og.ORG_ID AND og.ORG_TYPE_ID = 'EO' inner join ibs.T9_YEAR_Q q on q.QTD_CD=right(sy.MEASURE_DT,5) where sy.MEASURE_DT like {#EXAM_YEAR#}||'%' and q.QTD<={#EXAM_Q#} )sy inner join ibs.T5_EMP_BZJX em on em.EMP_ID=sy.EMP_ID and em.EXAM_YEAR={#EXAM_YEAR#} and em.EXAM_Q={#EXAM_Q#} left join ibs.T5_EMP_GDQ_OR_GZ gd on gd.MEASURE_DT=sy.MEASURE_DT and sy.EMP_ID=gd.EMP_ID and gd.STATUS='1' and gd.PSTN_TYPE=sy.PSTN_TYPE
left join ibs.T5_EMP_CERTIFICATE ce on ce.EMP_ID=sy.EMP_ID left join ibs.T9_PSTN_TYPE ty on ty.SUB_PSTN_TYPE=sy.SUB_PSTN_TYPE and ty.PSTN_TYPE=sy.PSTN_TYPE where {#condition#}

